sqlMap.select:
select distinct * from ( select distinct a.survey_id as surveyId, b.cn as userId, b.displayname as userName1, b.displayname2 as userName2, b.mail as email, a.company_id as companyId, a.tenant_id as tenantId from tbl_survey_participant a join tbl_usermaster b on a.tenant_Id = b.tenant_Id and a.tenant_Id = #tenantId# and b.cn not in (select cn from tbl_usermaster_retire where tenant_id = #tenantId#) and ( (a.user_type = 'jikchek' and b.extensionattribute8 = a.user_id) or (a.user_type = 'jikwi' and b.extensionattribute7 = a.user_id) or (a.user_type = 'comp' and b.physicaldeliveryofficename = a.user_id) or (a.user_type = 'user' and b.cn = a.user_id) or (a.user_type = 'dept' and b.department = a.user_id)
or (a.user_type = 'group' and b.cn in ( select distinct d.cn from tbl_permissiongroupinfo c join tbl_usermaster d on d.tenant_id = c.tenant_id AND d.tenant_Id = #tenantId# AND c.company_id = #companyId# where c.group_id = a.user_id and ( (c.member_type = 'JIKCHEK' and d.extensionattribute8 = c.member_id) or (c.member_type = 'JIKWI' and d.extensionattribute7 = c.member_id) or (c.member_type = 'ORGAN' and d.physicaldeliveryofficename = c.member_id) or (c.member_type = 'USER' and d.CN = c.member_id) or (c.member_type = 'DEPT' and d.department = c.member_id)
) ) ) ) where a.survey_id = #surveyId# and a.tenant_id = #tenantId# and a.company_id = #companyId#
union select distinct b.survey_id as surveyId, cn as userId, displayname as userName1, displayname2 as userName2, mail as email, PHYSICALDELIVERYOFFICENAME as companyId, tenant_id as tenantId from ( select distinct p.member_id as member_id , p.member_type as member_type, s.survey_id as survey_id, s.user_type as user_type from tbl_permissiongroupinfo p join tbl_survey_participant s on s.user_id = p.group_id and p.tenant_id = s.tenant_id and s.survey_id = #surveyId#
) b join tbl_usermaster a on cn in ( select ad.cn from tbl_addjobmaster ad where tenant_id = #tenantId# and ( b.user_type = 'dept' and b.member_id = ad.deptid or (b.user_type = 'jikwi' and b.member_id = ad.jobid) or (b.user_type = 'jikchek' and b.member_id = ad.jobid) )) where a.PHYSICALDELIVERYOFFICENAME = #companyId# and tenant_id = #tenantId# union select distinct d.survey_id as surveyId, a.cn as userId, a.displayname as userName1, a.displayname2 as userName2, a.mail as email, a.PHYSICALDELIVERYOFFICENAME as companyId, a.tenant_id as tenantId from tbl_usermaster a join ( select distinct ad.cn as cn, s.survey_id as survey_id from tbl_addjobmaster ad join tbl_survey_participant s on ad.tenant_id = s.tenant_id and s.survey_id = #surveyId# and s.tenant_id = #tenantId# where (s.user_type = 'dept' and s.user_id = ad.deptid ) or (s.user_type = 'jikwi' and s.user_id = ad.jobid ) or (s.user_type = 'jikchek' and s.user_id = ad.jobid ) ) d on d.cn = a.cn where a.PHYSICALDELIVERYOFFICENAME = #companyId# and tenant_id = #tenantId#
) as plusaddjob

sqlMap.insert:

insert into tbl_survey_attachfile (
	target_id,  survey_id,  target_type,  file_nm, file_size, file_path, file_url, company_id,  tenant_id
)
values (
	#targetId#, #surveyId#, #targetType#, #fname#, #fileSize#, #fpath#,  #furl#, #companyId#, #tenantId#
)


insert into tbl_survey_respondent (
	response_id,  survey_id,  user_id,  user_name1,  user_name2, email, image, dept_id, dept_name1, dept_name2, response_date, company_id, tenant_id
)
values (
	#responseId#, #surveyId#, #userId#, #userName1#, #userName2#, #email#, #image#, #deptId#, #deptName1#, #deptName2#, #responseDate#, #companyId#, #tenantId#
)
